"""PLAN 단계 — 토폴로지 정렬."""

from __future__ import annotations

from collections import defaultdict, deque

from mantis.models.node import NodeInfo, EdgeInfo


def topological_sort(
    nodes: dict[str, NodeInfo],
    edges: list[EdgeInfo],
) -> list[str]:
    """Kahn's algorithm 토폴로지 정렬.

    같은 레벨 노드는 position(y, x)으로 정렬하여 결정론적 순서.

    Raises:
        ValueError: 순환 감지.
    """
    in_degree: dict[str, int] = {nid: 0 for nid in nodes}
    adjacency: dict[str, list[str]] = defaultdict(list)

    for edge in edges:
        if edge.source_node in nodes and edge.target_node in nodes:
            adjacency[edge.source_node].append(edge.target_node)
            in_degree[edge.target_node] = in_degree.get(edge.target_node, 0) + 1

    # in-degree 0 노드부터 시작 (position 정렬)
    queue = deque(
        sorted(
            [nid for nid, deg in in_degree.items() if deg == 0],
            key=lambda nid: nodes[nid].position,
        )
    )

    order: list[str] = []
    while queue:
        # 현재 레벨 전부 처리
        level_size = len(queue)
        level_nodes = []
        for _ in range(level_size):
            level_nodes.append(queue.popleft())

        # position 정렬
        level_nodes.sort(key=lambda nid: nodes[nid].position)
        order.extend(level_nodes)

        for nid in level_nodes:
            for neighbor in adjacency[nid]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

    if len(order) != len(nodes):
        raise ValueError(
            f"순환 감지: 정렬된 노드 {len(order)}개 != 전체 {len(nodes)}개"
        )

    return order
